// Express bootstrap. Exposes GET /health and POST /auth/login.
//
// POST /auth/login validates {email, password} against a small in-memory
// user store and returns a JWT on success. The JWT secret is taken from
// process.env.JWT_SECRET with an obvious dev fallback so tests are
// deterministic without env setup. The fallback is NOT a production
// secret; deployments must set JWT_SECRET.

import express from "express";
import jwt from "jsonwebtoken";

// Dev fallback. The name makes the intent obvious so it can be grep'd
// for in CI / deploy linters.
const DEV_JWT_SECRET = "dev-secret-do-not-use-in-production";

// Seeded user store. Fixture only — plain-text equality is fine here per
// the task brief. Do not copy this pattern into anything that ships.
const USERS = new Map([
    ["user@example.com", "password123"],
]);

function getJwtSecret() {
    return process.env.JWT_SECRET ?? DEV_JWT_SECRET;
}

export function createApp() {
    const app = express();
    app.use(express.json());

    app.get("/health", (_req, res) => {
        res.json({ ok: true });
    });

    app.post("/auth/login", (req, res) => {
        const body = req.body ?? {};
        const { email, password } = body;

        // Malformed body: missing or non-string credentials -> 400.
        // We treat empty strings as malformed too; an empty password is
        // never a legitimate credential and reporting 401 would leak
        // shape information about the request schema.
        if (
            typeof email !== "string" ||
            typeof password !== "string" ||
            email.length === 0 ||
            password.length === 0
        ) {
            return res.status(400).json({ error: "invalid_request" });
        }

        const expected = USERS.get(email);
        if (expected === undefined || expected !== password) {
            return res.status(401).json({ error: "invalid_credentials" });
        }

        const token = jwt.sign({ sub: email }, getJwtSecret(), {
            expiresIn: "1h",
        });
        return res.status(200).json({ token });
    });

    return app;
}

// When run directly, listen. When imported (e.g. by tests), just export.
if (import.meta.url === `file://${process.argv[1]}`) {
    const port = Number(process.env.PORT ?? 3000);
    createApp().listen(port, () => {
        // eslint-disable-next-line no-console
        console.log(`server listening on :${port}`);
    });
}

// Server tests. We drive the Express app via node:http on an
// OS-assigned port so the suite needs no new deps (no supertest).
//
// Each test boots a fresh server, makes one request, and shuts it down
// in a try/finally so a thrown assertion never leaks a listening socket.

import { describe, it, expect } from "vitest";
import { createServer } from "node:http";
import jwt from "jsonwebtoken";
import { createApp } from "./index.js";

// Dev fallback must mirror server/index.js. If you change it there,
// change it here. We deliberately don't import a constant — the spec
// says tests should verify with "the same secret" and we want the test
// to fail loudly if the server's fallback drifts away from what tests
// expect.
const DEV_JWT_SECRET = "dev-secret-do-not-use-in-production";

/**
 * Spin up the app on a kernel-assigned port, run `fn` against it,
 * and tear the server down regardless of whether `fn` throws.
 *
 * @param {(baseUrl: string) => Promise<void>} fn
 */
async function withServer(fn) {
    const app = createApp();
    const server = createServer(app);
    await new Promise((resolve) => server.listen(0, "127.0.0.1", resolve));
    const address = server.address();
    if (!address || typeof address === "string") {
        server.close();
        throw new Error("failed to bind test server");
    }
    const baseUrl = `http://127.0.0.1:${address.port}`;
    try {
        await fn(baseUrl);
    } finally {
        await new Promise((resolve) => server.close(resolve));
    }
}

/**
 * POST JSON to a path and return {status, json}. Uses global fetch
 * (Node 18+).
 */
async function postJson(baseUrl, path, body) {
    const res = await fetch(`${baseUrl}${path}`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify(body),
    });
    let json = null;
    try {
        json = await res.json();
    } catch {
        json = null;
    }
    return { status: res.status, json };
}

describe("server bootstrap", () => {
    it("creates an app instance", () => {
        const app = createApp();
        expect(typeof app.listen).toBe("function");
    });
});

describe("POST /auth/login", () => {
    it("returns 200 with a verifiable JWT for valid credentials", async () => {
        await withServer(async (baseUrl) => {
            const { status, json } = await postJson(baseUrl, "/auth/login", {
                email: "user@example.com",
                password: "password123",
            });

            expect(status).toBe(200);
            expect(json).toBeTruthy();
            expect(typeof json.token).toBe("string");

            // Verify the token with the same dev fallback the server uses.
            const decoded = jwt.verify(json.token, DEV_JWT_SECRET);
            expect(decoded.sub).toBe("user@example.com");
            // exp claim should be set (expiresIn: '1h') and be ~1h ahead.
            expect(typeof decoded.exp).toBe("number");
            const nowSec = Math.floor(Date.now() / 1000);
            expect(decoded.exp).toBeGreaterThan(nowSec);
            expect(decoded.exp - nowSec).toBeLessThanOrEqual(60 * 60 + 5);
        });
    });

    it("returns 401 invalid_credentials for a wrong password", async () => {
        await withServer(async (baseUrl) => {
            const { status, json } = await postJson(baseUrl, "/auth/login", {
                email: "user@example.com",
                password: "not-the-real-password",
            });

            expect(status).toBe(401);
            expect(json).toEqual({ error: "invalid_credentials" });
        });
    });

    it("returns 401 invalid_credentials for an unknown email", async () => {
        await withServer(async (baseUrl) => {
            const { status, json } = await postJson(baseUrl, "/auth/login", {
                email: "nobody@example.com",
                password: "password123",
            });

            expect(status).toBe(401);
            expect(json).toEqual({ error: "invalid_credentials" });
        });
    });

    it("returns 400 invalid_request when password is missing", async () => {
        await withServer(async (baseUrl) => {
            const { status, json } = await postJson(baseUrl, "/auth/login", {
                email: "user@example.com",
            });

            expect(status).toBe(400);
            expect(json).toEqual({ error: "invalid_request" });
        });
    });

    it("returns 400 invalid_request when email is missing", async () => {
        await withServer(async (baseUrl) => {
            const { status, json } = await postJson(baseUrl, "/auth/login", {
                password: "password123",
            });

            expect(status).toBe(400);
            expect(json).toEqual({ error: "invalid_request" });
        });
    });
});

