// LoginForm: posts email/password to /auth/login and surfaces the
// returned JWT or an error message. Designed to be small, testable
// without a full DOM, and accessible by default.
//
// Public contract (auth-neb.2):
//   - Default export is a function component named `LoginForm`.
//   - Renders a <form> with controlled email/password inputs and a
//     submit button labelled "Log in".
//   - On submit: POST {email, password} as JSON to props.endpoint
//     (default "/auth/login").
//   - On 200: reads {token} from the JSON body, shows it in a node
//     with data-testid="login-token", and fires the optional
//     onSuccess(token) callback.
//   - On non-2xx or network/parse failure: shows a message in a node
//     with data-testid="login-error" and fires the optional
//     onError(message) callback.
//   - Submit button is disabled while a request is in flight.
//
// Accessibility:
//   - Every input has an associated <label htmlFor>.
//   - Error node uses role="alert" so screen readers announce it.
//   - Token display uses aria-live="polite" so success is announced
//     without stealing focus.
//   - Submit button gets aria-busy while pending.
//
// Testability:
//   - The component is named so renderToStaticMarkup snapshots stay
//     readable.
//   - data-testid hooks on token + error nodes give tests stable
//     selectors without coupling to copy.

import React from "react";

const DEFAULT_ENDPOINT = "/auth/login";
const GENERIC_ERROR = "Invalid credentials";

export default function LoginForm({
    endpoint = DEFAULT_ENDPOINT,
    onSuccess,
    onError,
} = {}) {
    const [email, setEmail] = React.useState("");
    const [password, setPassword] = React.useState("");
    const [pending, setPending] = React.useState(false);
    const [token, setToken] = React.useState(null);
    const [error, setError] = React.useState(null);

    async function handleSubmit(event) {
        event.preventDefault();
        if (pending) return;
        setPending(true);
        setToken(null);
        setError(null);

        try {
            const res = await fetch(endpoint, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ email, password }),
            });

            if (!res.ok) {
                // Try to surface a server-provided message; fall back to
                // a generic line. We never echo raw HTTP bodies into the
                // DOM because the server may return non-JSON on 5xx.
                let message = GENERIC_ERROR;
                try {
                    const payload = await res.json();
                    if (payload && typeof payload === "object") {
                        if (typeof payload.error === "string") {
                            message = payload.error;
                        } else if (typeof payload.message === "string") {
                            message = payload.message;
                        }
                    }
                } catch (_parseErr) {
                    // keep generic message
                }
                setError(message);
                if (typeof onError === "function") onError(message);
                return;
            }

            const payload = await res.json();
            const received = payload && typeof payload.token === "string"
                ? payload.token
                : null;
            if (received) {
                setToken(received);
                if (typeof onSuccess === "function") onSuccess(received);
            } else {
                const message = "Login response missing token";
                setError(message);
                if (typeof onError === "function") onError(message);
            }
        } catch (_networkErr) {
            const message = "Could not reach the server. Please try again.";
            setError(message);
            if (typeof onError === "function") onError(message);
        } finally {
            setPending(false);
        }
    }

    return (
        <form className="login-form" onSubmit={handleSubmit} noValidate>
            <div className="login-form__field">
                <label htmlFor="login-email">Email</label>
                <input
                    id="login-email"
                    name="email"
                    type="email"
                    autoComplete="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    disabled={pending}
                />
            </div>
            <div className="login-form__field">
                <label htmlFor="login-password">Password</label>
                <input
                    id="login-password"
                    name="password"
                    type="password"
                    autoComplete="current-password"
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    disabled={pending}
                />
            </div>
            <button
                type="submit"
                disabled={pending}
                aria-busy={pending ? "true" : "false"}
            >
                {pending ? "Logging in…" : "Log in"}
            </button>
            {error ? (
                <p
                    className="login-form__error"
                    data-testid="login-error"
                    role="alert"
                >
                    {error}
                </p>
            ) : null}
            {token ? (
                <p
                    className="login-form__token"
                    data-testid="login-token"
                    aria-live="polite"
                >
                    {token}
                </p>
            ) : null}
        </form>
    );
}

// React shell. Mounts the LoginForm built for auth-neb.2 and keeps the
// fixture's <h1> so the component shape stays recognizable to existing
// trace assertions.

import React from "react";
import LoginForm from "./LoginForm.jsx";

export default function App() {
    return (
        <div className="app">
            <h1>node-react-auth fixture</h1>
            <LoginForm />
        </div>
    );
}

// Minimal coverage for the LoginForm component (auth-neb.2).
//
// Why renderToStaticMarkup:
//   The spec asks us to assert that "calling LoginForm returns a React
//   element whose tree includes a form, email input, password input,
//   and submit button". LoginForm uses hooks (useState), so calling it
//   directly outside a React renderer throws "Invalid hook call".
//   Rendering with react-dom/server (already a transitive dep) is the
//   lightest weight way to exercise the real render path without
//   pulling jsdom, @testing-library/react, or other DOM stack into
//   this fixture's package.json. The assertions stay structural
//   (substring + regex on the produced HTML), so they fail loudly if
//   the form shape regresses but don't snapshot copy.

import { describe, it, expect } from "vitest";
import { renderToStaticMarkup } from "react-dom/server";
import React from "react";
import LoginForm from "./LoginForm.jsx";

describe("LoginForm", () => {
    it("is a React component (function)", () => {
        expect(typeof LoginForm).toBe("function");
    });

    it("renders a form with email + password inputs and a submit button", () => {
        const html = renderToStaticMarkup(<LoginForm />);

        // The form is the top-level element so the surrounding wrapper
        // is the form tag itself.
        expect(html).toMatch(/<form\b/);
        // Inputs: assert each type is present. The attribute order is
        // controlled by React's renderer, but `type="email"` etc.
        // always appear verbatim.
        expect(html).toMatch(/<input[^>]*type="email"/);
        expect(html).toMatch(/<input[^>]*type="password"/);
        // Submit button. We don't pin the label because copy might
        // change ("Log in" vs "Sign in") — pin the role+type pair.
        expect(html).toMatch(/<button[^>]*type="submit"/);
    });

    it("renders without an error or token node on first paint", () => {
        // Both async slots stay hidden until the user submits.
        // Regression guard: a future refactor that forgets to gate
        // these on state would leak empty <p data-testid=...> nodes.
        const html = renderToStaticMarkup(<LoginForm />);
        expect(html).not.toMatch(/data-testid="login-error"/);
        expect(html).not.toMatch(/data-testid="login-token"/);
    });

    it("associates each input with a label by id", () => {
        // Accessibility regression guard. If a future change rips out
        // the <label htmlFor> wiring, keyboard + screen reader users
        // lose the form. Match the pair generically so refactors that
        // rename the ids (but keep them paired) still pass.
        const html = renderToStaticMarkup(<LoginForm />);
        const labelFors = Array.from(
            html.matchAll(/<label[^>]*for="([^"]+)"/g),
        ).map((m) => m[1]);
        const inputIds = Array.from(
            html.matchAll(/<input[^>]*\bid="([^"]+)"/g),
        ).map((m) => m[1]);
        expect(labelFors.length).toBeGreaterThanOrEqual(2);
        for (const f of labelFors) {
            expect(inputIds).toContain(f);
        }
    });
});

// Local vitest config for the fixture.
//
// Without this, vitest walks up the directory tree looking for a
// config and finds the parent E2E harness config at
// `.claude/tests/e2e/vitest.config.ts`, which scopes `include` to
// `specs/**/*.spec.ts` for the harness's own L3/L4 specs. That makes
// the fixture's own `server/index.test.js` and any client tests
// invisible to a plain `npm test` invocation inside the fixture.
//
// Pinning `include` here restores vitest's default-ish discovery
// (any `*.test.{js,ts,jsx,tsx}` under the fixture, minus node_modules).
//
// Keep this file minimal: the harness owns its own config above; this
// only exists to prevent that config from leaking down into the
// fixture's test runs.

import { defineConfig } from "vitest/config";

export default defineConfig({
    test: {
        include: ["**/*.test.{js,ts,jsx,tsx}"],
        exclude: ["**/node_modules/**", "**/dist/**"],
    },
});

